#include<bits/stdc++.h>
using namespace std;
int dx[]={0,-1,0,1,1,-1,1,-1};
int dy[]={1,0,-1,0,1,1,-1,-1};
bool v[1001][1001]={0};
long long a[1001][1001],n,ans1,ans2;
int dfs(int x,int y){
    int flag1=1;
    int flag2=1;
    v[x][y]=1;
    for(int i=0;i<=7;i++){
        int mx=x+dx[i];
        int my=y+dy[i];
        if(mx<=0||my<=0||mx>n||my>n) continue;

        if(a[mx][my]>a[x][y]){
           flag1=0; 
        }else if(a[mx][my]<a[x][y]){
            flag2=0;
        }else{
            if(v[mx][my]) continue;
            int ans=dfs(mx,my);
            if(ans==0){
                flag1=0;
                flag2=0;
            }else if(ans==1){
                flag2=0;
            }else if(ans==2){
                flag1=0;
            }
        }
    }
    return flag1+flag2*2;
}
int main(){
    cin>>n;
    for(int i=1;i<=n;i++){
        for(int j=1;j<=n;j++){
            cin>>a[i][j];
        }
    }
    for(int i=1;i<=n;i++){
        for(int j=1;j<=n;j++){
            if(!v[i][j]){
                int ans=dfs(i,j);
                if(ans==1){
                    ans1++;
                }else if(ans==2){
                    ans2++;
                }else if(ans==3){
                    ans1++;
                    ans2++;
                }
            }
        }
    }
    cout<<ans1<<" "<<ans2;
    return 0;
}
